                bug_commenter?: string;
                bug_subscriber?: string;
                structural_subscriber?: string;
                owner?: string;
                affected_user?: string;
                /** @description Show only bugs with patches available. */
                has_patch?: string;
                /** @description Show only bugs associated with a CVE */
                has_cve?: string;
                /** @description Tags String or list of strings for tags to search. To exclude, prepend a '-', e.g. '-unwantedtag' */
                tags?: string;
                /** @description Tags combination Search for any or all of the tags specified. */
                tags_combinator?: "Any" | "All";
                /** @description Omit bugs marked as duplicate, */
                omit_duplicates?: string;
                /** @description Status upstream Indicates the status of any remote watches associated with the bug. Possible values include: pending_bugwatch, hide_upstream, resolved_upstream, and open_upstream. */
                status_upstream?: string;
                /** @description Milestone Show only bug tasks targeted to this milestone. */
                milestone?: string;
                /** @description Component Distribution package archive grouping. E.g. main, universe, multiverse */
                component?: string;
                nominated_for?: string;
                /** @description Exclude bugs with packages specified */
                has_no_package?: string;
                /** @description Search for bugs that are linked to branches or for bugs that are not linked to branches. */
                linked_branches?: "Show all bugs" | "Show only Bugs with linked Branches" | "Show only Bugs without linked Branches";
                /** @description Search for bugs that have been modified since the given date. */
                modified_since?: string;
                /** @description Search for bugs that have been created since the given date. */
                created_since?: string;
                /** @description Search for bugs that were created before the given date. */
                created_before?: string;
                /** @description Omit bugs targeted to a series */
                omit_targeted?: string;
                /** @description Search for bugs that are linked to blueprints or for bugs that are not linked to blueprints. */
                linked_blueprints?: "Show all bugs" | "Show only Bugs with linked Blueprints" | "Show only Bugs without linked Blueprints";
